-- Generated from Shanghai sub-area markdown files (with cover images)
WITH input_rows(attraction_name_zh, sort_order, name_en, name_zh, body, cover_image_path) AS (
  VALUES
  (' 田子坊', 0, 'Taikang Road Main Entrance', '田子坊 · 泰康路主入口', '<p>The Taikang Road Main Entrance sits at Lane 210, Taikang Road, the southern end of Tianzifang. The archway is built of bluestone, with the characters "田子坊" calligraphed by the renowned Chinese painter Huang Yongyu. Right by the entrance is a small cultural-creative gift shop and a popular photo wall where visitors queue year-round for pictures. Stepping through, you step into the shikumen lilong cluster and creative boutiques — the first movement of Tianzifang''s "old Shanghai, new art" mood.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_01.png'),
  (' 田子坊', 1, 'Shikumen Lilong Architectural Cluster', '田子坊 · 石库门里弄建筑群', '<p>The Shikumen lilong area is the historic heart of Tianzifang, covering about 7.2 hectares. Most shikumen houses were built in the 1920s—1930s: red-brick plaster walls, black-lacquered wooden doors, brass knockers, semi-circular or Baroque carved lintels, with sky-bridges and wing-rooms staggered along narrow lanes. The buildings have been converted into creative shops, galleries, cafés and designer studios, but the original façades remain largely intact. Walking along Lanes 210 / 248 / 274, you''ll see laundry poles, cast-iron window grilles and old shikumen plaques — the best living slice of Shanghai''s "alley-meets-modern" character.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_02.png'),
  (' 田子坊', 2, 'Chen Yifei Former Studio', '田子坊 · 陈逸飞工作室旧址', '<p>The former studio sits at 2-A, Lane 210, Taikang Road, a two-storey shikumen building of about 170 square meters. From 1998 until his death in 2005, the celebrated oil painter Chen Yifei worked here, completing several major series including "Old Shanghai Dreams" and "Ladies." The studio''s signature is its tangle of overhead wires and mismatched window shapes against the sky. Since October 2025, the Shanghai and Huangpu governments have jointly opened the space to the public for free, restoring it to its working-condition look. Visitors can see easels, oil paints, original catalogues, and letters — a must-visit for art lovers and Chen Yifei fans.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_03.png'),
  (' 田子坊', 3, 'Shoubai Art Center', '田子坊 · 守白艺术中心', '<p>Located inside Lane 210, Taikang Road, Shoubai Art Center was founded by Hai pai painter and paper-cutting artist Li Shoubai. The center regularly displays Li Shoubai''s heavy-color paintings and paper-cut works themed on old Shanghai street scenes, qipao, opera, and everyday life — vivid colors and rich compositions. The first floor houses the exhibition and creative-retail zone; the second floor often hosts interactive workshops (paper-cutting, woodblock printing, fan painting, etc.) where visitors can try intangible cultural heritage hands-on. The center also regularly invites domestic and overseas artists for joint exhibitions and lectures — a day-into-night cultural parlor.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_04.png'),
  (' 田子坊', 4, 'Painter''s Building Rooftop', '田子坊 · 画家楼天台', '<p>The "Painter''s Building" is a shikumen-converted artists'' residence deep inside Lane 210, Taikang Road, with ground and first floors housing galleries, studios and creative shops. The rooftop is open to visitors and offers a wide panoramic view: to the east, the urban skyline toward Dapuqiao; to the south, an unbroken sea of red-tile shikumen roofs laced with black overhead wires — the classic "old Shanghai" sightline; to the west, occasional glimpses of distant high-rises. Many photographers come specifically for the "red tiles + skyscrapers" contrast, especially at sunset. Pair it with the retro phone booth, graffiti wall, and narrow lanes for the full Tianzifang photo trail.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_05.png'),
  (' 田子坊', 5, 'Demete / Odor Library', '田子坊 · 气味图书馆', '<p>The Odor Library (the Chinese partner of the US Demeter Fragrance Library brand) sits inside Lane 248, Taikang Road, and is one of China''s earliest homegrown brands to turn "city scents," "childhood memories," and "emotional scents" into bottled perfumes. The compact shop displays dozens of thematically named fragrances on its walls — "Garden After Rain," "Old Book Page," "Grandma''s Kitchen," "Old Shanghai Lane" — each tied to a concrete scene or memory. Customers can freely sniff, commission a custom scent, or pick up 30ml travel-size gift boxes. For travelers who believe a city can be captured by smell, it is Tianzifang''s most distinctive "olfactory souvenir" stop.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_06.png'),
  (' 田子坊', 6, 'Jin Fen Shi Jia (Golden Powder Family)', '田子坊 · 金粉世家', '<p>Tucked deep inside Lane 248, Taikang Road, Jin Fen Shi Jia is one of Tianzifang''s longest-running and most reputable qipao + retro photo studios. The shop stocks dozens of old-Shanghai qipao (silk, velvet, linen-cotton), plus men''s changshan, mandarin jackets, student uniforms, and vintage accessories. Customers can try them on, then be photographed by a pro in the studio or out in the lilong lanes — with retro phone booths, vintage bicycles and gramophones as classic props. The shop also rents costumes and props for self-shooters. Whether you want an "old Shanghai family portrait" or a "qipao shoot with the girls," Jin Fen Shi Jia is one of the most reliable choices in Tianzifang.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_07.png'),
  (' 田子坊', 7, 'Lane 248 (248 Nong)', '田子坊 · 248 弄弄堂', '<p>Lane 248 is one of Tianzifang''s three principal lanes (the others being Lanes 210 and 274), running north from Taikang Road for about 200 meters. Lined with dozens of original designer shops, hand-made leather ateliers, independent bookstores, vintage silverware stores, and small cafés/dessert spots, Lane 248 is narrower and quieter than the main 210 Lane, ideal for slow wandering. You can often watch designers hand-finishing leather goods, blending perfume, or throwing pottery inside the shops. Street performers — accordion, hand drum — regularly play at the lane mouth, lending the space a free, easy-going mood.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_08.png'),
  (' 田子坊', 8, 'Lane 274 Art Corridor (274 Nong)', '田子坊 · 274 弄艺术长廊', '<p>Lane 274 is the northernmost of Tianzifang''s three main lanes, connecting Taikang Road in the south to Jianguo Middle Road in the north. It is the most "art-saturated" of the three, lined with contemporary galleries (Base Art Center, Ren Weiyin Painting Museum, and others), emerging-artist studios, independent publishers, photography galleries, and small art-book cafés. It hosts numerous solo, group, video, and salon-style exhibitions each year; some galleries are free, others charge 20—50 RMB/visit or require a drink voucher. Many gallery façades are regularly repainted with new large-scale graffiti and installations, making Lane 274 a "see-shoot-wander" all-in-one core section of Tianzifang.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/tianzifang_sa_09.png'),
  ('东方明珠广播电视塔', 0, 'Ticket Gate', '检票口', '<p>The Ticket Gate of the Oriental Pearl TV Tower is located at the south podium entrance, adjacent to the Lujiazui Riverside Walk and facing Century Avenue. Designed with a "bright pearl" motif, its facade combines silver-white metal and glass, paired with LED ticker displays showing real-time queue and boarding information. Visitors must present their e-ticket QR code or ID card (swipe-to-enter), and pass through security and metal detectors. Inside the gate is the prelude hall, offering accessible lanes, luggage lockers, a baby-care room, and group reception counters. High-speed elevators at 9 m/s take guests directly to each observation level, with no fixed batch restrictions during opening hours. On holidays, arrive an hour early to avoid peak queues; on regular days, completing the ticket check before 9:30 offers a near-private tower experience.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_01.png'),
  ('东方明珠广播电视塔', 1, 'Main Observation Deck', '主观光层', '<p>The Main Observation Deck sits inside the tower''s third sphere at 263 meters — the original core observation level open to the public. With a 20-meter inner diameter, the circular walkway is fully glazed, offering sweeping views of the Bund''s historic buildings, Pudong''s skyscrapers, and the winding Huangpu River. Sunset (around 17:30–18:30, seasonally shifting) brings Shanghai''s most celebrated "golden hour" as city lights come on. The deck features transparent floor windows, photo spots, vending machines, and a light-snack corner. A wide-angle lens and a phone''s night mode are recommended; be aware of glass glare, so press close to the glass or pick a column-free spot. The level connects by elevator to the 259m Skywalk, 350m Space Capsule, 78m "More Shanghai" immersive show, and the 0m Shanghai History Exhibition.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_02.png'),
  ('东方明珠广播电视塔', 2, 'Meter Space Capsule', '米太空舱', '<p>The 351-Meter Space Capsule sits inside the tower''s highest sphere, originally completed in 2008 and upgraded in 2023 into a "space + metaverse" immersive experience venue. With a 14-meter inner diameter, its walls combine starry ceilings and mirrored metals, paired with holographic projections and surround sound, creating a "spacewalk" atmosphere. Highlights include 360° views of Shanghai''s four skylines (Lujiazui, the Bund, North Bund, Xuhui Riverside), AI interactive photo booths (generating "astronaut" souvenir images), VR immersive "China Space Station" simulations, and remote-controlled "Yutu Lunar Rover" demos on the floor. The outer deck is a closed observation corridor with double-glazed safety glass, offering unobstructed full-city photography. Capacity is capped at 30 people with 10-minute rotations.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_03.png'),
  ('东方明珠广播电视塔', 3, 'Transparent Glass Skywalk (Sky Observatory)', '全透明悬空观光廊', '<p>The Transparent Glass Skywalk runs along the underside of the tower''s second sphere at 259 meters. The circular walkway is 1.8 meters wide and approximately 150 meters long, projecting from three sides of the sphere and suspended over the Huangpu River. Both the floor and railings are 24mm triple-laminated tempered glass with 99.7% light transmission — a true "walking on clouds" experience. Below the walkway, visitors can see Lujiazui''s core traffic, the tower''s signature "pearl-string" silhouette, the riverside promenade, and the Bund''s historic skyline. The corridor features 6 "brave photo spots," with LED screens embedded beneath the glass that play a "star river" animation at night. The glass can support up to 800 kg per square meter, with a limit of 8 people per section. The skywalk is temporarily closed during strong winds, rain, or snow.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_04.png'),
  ('东方明珠广播电视塔', 4, 'Outdoor Observation Terrace', '户外观光层', '<p>The Outdoor Observation Terrace is a 360-degree circular platform at 350 meters on the tower''s main shaft, approximately 200 meters long and 2.5 meters wide — the highest open-air viewing area on the tower. It features 1.3m tempered-glass railings, anti-slip aluminum flooring, 24/7 surveillance, an emergency station, and safety ropes. From here, visitors look up at the 351m Space Capsule "jade pillar" and down on the S-shaped bend of the Huangpu River and the Bund skyline. A breeze of Beaufort 3–5 makes for a refreshing experience; the terrace closes in winds above Beaufort 6. Access is via a dedicated gate on the 350m elevator level. No seating is provided; a 15–30 minute stay is recommended.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_05.png'),
  ('东方明珠广播电视塔', 5, '"More Shanghai" 360° Immersive Multimedia Show', '更上海环动多媒体秀', '<p>The "More Shanghai" Immersive Multimedia Show is located at 78 meters on the tower''s main shaft. The theater has a 30-meter inner diameter with a 360° wraparound screen and a synchronized "motion floor" projection; seats rotate 360 degrees. The 10-minute show uses five chapters — River, Sea, Tide, Wind, Charm — to trace Shanghai''s century-long evolution: from the 1843 treaty-port opening, 1920s Bund construction, 1949 liberation, 1990 Pudong development, 2010 World Expo, 2020 urban renewal, to 2035 planning vision. Original music and 6.1-channel surround sound complete the immersive experience. Capacity is 80 people, with a show every 15 minutes. It is best watched as a mid-tour interlude, serving as a "city-background lesson" before ascending the main observation levels.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_06.png'),
  ('东方明珠广播电视塔', 6, 'Shanghai History Development Exhibition Hall', '上海城市历史发展陈列馆', '<p>The Shanghai History Development Exhibition Hall occupies approximately 6,000 square meters on Level 0 of the Oriental Pearl TV Tower''s podium, one of China''s earliest "tower + museum" themed venues. The hall is divided into five sections — Prelude, Shanghai before the Treaty Port, Rise of the Modern City, New China''s Shanghai, and Pudong Development &amp; New Shanghai — displaying more than 1,000 items including vintage photographs, archives, wax figure scenes, physical models, and interactive installations. Highlights include:</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/oriental_pearl_radio_television_tower_sa_07.png'),
  ('陆家嘴金融区', 0, 'Lujiazui Central Greenland', '陆家嘴中心绿地', '<p>Lujiazui Central Greenland, located at 717 Lujiazui Ring Road, Pudong New Area, is a rare open urban green space situated at the heart of Shanghai''s skyscraper cluster. Covering approximately 100,000 square meters and planted with cool-season turf imported from Europe, it features a striking steel "Pearl" sculpture and a circular sunken plaza at its center. Surrounded by the Jin Mao Tower, Shanghai World Financial Center, and Shanghai Tower—the three tallest buildings in China—it creates a remarkable "city within a garden, garden within a city" experience. Connected to the Huangpu River, the Oriental Pearl TV Tower, and the Riverside Promenade, it serves as a "green living room" for office workers and tourists alike, and is especially beautiful in spring when magnolias bloom and in autumn when ginkgo leaves turn golden.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_01.png'),
  ('陆家嘴金融区', 1, 'Oriental Pearl TV Tower (Oriental Pearl Radio & Television Tower)', '东方明珠广播电视塔', '<p>The Oriental Pearl TV Tower, located at 1 Century Avenue, Pudong New Area, stands 467.9 meters tall and was opened in 1994, ranking as the 6th tallest tower in Asia and 9th in the world. Its structure consists of three 9-meter-diameter pillars and three spheres of varying sizes connected by space capsules, creating the iconic "large and small pearls falling on a jade plate" silhouette that has become a symbol of Shanghai''s skyline. The tower features the Main Observation Deck (263m), the transparent Sky Walk (259m), the Space Capsule (351m), the outdoor Observation Deck (350m), a Revolving Restaurant (267m), and the Shanghai Museum of Urban Development History, making it one of the best vantage points for viewing Shanghai''s day and night scenery on both sides of the Huangpu River. The plaza at its base hosts various city festivals, and the "Dynamic Shanghai" multimedia show inside provides an immersive experience of Shanghai''s century-long urban transformation.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_02.png'),
  ('陆家嘴金融区', 2, 'Shanghai Ocean Aquarium', '上海海洋水族馆', '<p>The Shanghai Ocean Aquarium, located at 1388 Lujiazui Ring Road, Pudong New Area, is adjacent to the Oriental Pearl TV Tower. With a building area of approximately 20,500 square meters, it opened in 2002 and is one of the largest and most diverse ocean aquariums in Asia. The facility features 9 themed exhibition zones including Asia, South America, Australia, Africa, Cold Water, Coastline, Deep Sea, and China zones, housing over 15,000 rare marine creatures from more than 450 species. Its most famous feature is the 155-meter-long underwater viewing tunnel—certified by Guinness World Records as one of the world''s longest ocean tunnels—where visitors can watch sharks, rays, and sea turtles swim overhead through transparent acrylic panels. The aquarium also features the Jellyfish Kingdom, Coral Sea, and Antarctic Penguin exhibits, making it an ideal destination for families, couples, and marine life enthusiasts.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_03.png'),
  ('陆家嘴金融区', 3, 'Jin Mao Tower', '金茂大厦', '<p>Jin Mao Tower, located at 88 Century Avenue, Pudong New Area, stands 420.5 meters tall with 88 above-ground floors and 3 basement levels. Completed and opened in 1999, it was the first building in mainland China to exceed 400 meters. Designed by the American architectural firm SOM, the building draws inspiration from classical Chinese pagodas with its tiered, tapering form, creating a "fountain pen tip" silhouette. Its facade combines aluminum alloy and granite curtain walls, making it highly recognizable. The complex integrates offices, hotels, sightseeing, and commerce, featuring the Grand Hyatt Shanghai (floors 53-87), the 88th-floor Observation Deck, and the spectacular 152-meter-tall "Time Tunnel" light corridor. From the 88th-floor observation deck, visitors can enjoy a 360-degree panoramic view of Shanghai, with the historic Bund and Lujiazui skyscrapers all visible. At night, the building''s illuminated peak becomes one of Shanghai''s most iconic skyline features.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_04.png'),
  ('陆家嘴金融区', 4, 'Shanghai World Financial Center (SWFC)', '上海环球金融中心', '<p>Shanghai World Financial Center, located at 100 Century Avenue, Pudong New Area, stands 492 meters tall with 101 above-ground floors and 3 basement levels, fully opened in August 2008. Designed by Japan''s Kohn Pedersen Fox (KPF), the building is nicknamed the "Bottle Opener" due to its distinctive trapezoidal aperture at the top. As one of the Lujiazui "Trio" skyscrapers, it integrates offices, hotels, sightseeing, and commerce, housing the Park Hyatt Shanghai (floors 79-93), observation decks on floors 94/97/100, and the "Sky Walk 100" experience at 492 meters. The 100th-floor observation sky lobby was certified by Guinness World Records as the world''s highest observation deck, offering a 360-degree panoramic view at 474 meters. Its transparent glass-floor sky walk provides an exhilarating experience. Together with Jin Mao Tower and Shanghai Tower, SWFC forms the iconic "three-legged" Lujiazui skyline—a symbol of China''s 30 years of reform and opening up.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_05.png'),
  ('陆家嘴金融区', 5, 'Wu Changshuo Memorial Hall', '吴昌硕纪念馆', '<p>The Wu Changshuo Memorial Hall, located at 15 Lujiazui East Road, Pudong New Area, is a dedicated memorial to Wu Changshuo (1844-1927), the master of Shanghai-style painting and calligraphy in late Qing and early Republican China, who excelled in poetry, painting, calligraphy, and seal carving. The memorial is housed in the "Yingchuan Xiaozhu" (Yingchuan Small Mansion)—a late Qing and early Republic era red-and-blue brick carved residence built in 1920, originally the home of Shanghai merchant Chen Guichun. Officially relocated to this site in May 2010, the building covers approximately 1,500 square meters and is recognized as a Shanghai Municipal Cultural Relic Protection Unit, renowned for its exquisite brick and wood carvings and nicknamed "Pudong Carved Building." The memorial features three main exhibition halls: "Wu Changshuo''s Life and Career," "Artistic Achievements," and "Poetry, Painting, Calligraphy, and Seal Works," displaying over 200 precious artifacts including works by Wu Changshuo and his disciples Qi Baishi, Pan Tianshou, Sha Menghai, Wang Geyi, and others. The site also includes the "Fou Pavilion" café and a cultural creative shop, making it a rare refined cultural oasis in the Lujiazui financial district.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_06.png'),
  ('陆家嘴金融区', 6, 'Century Avenue', '世纪大道', '<p>Century Avenue, located in Pudong New Area, is 5.5 kilometers long and 100 meters wide. Stretching east from Century Park to the Oriental Pearl TV Tower in Lujiazui and connecting directly with the Yan''an East Road Tunnel, it opened on April 18, 2000, and is one of the most important east-west arterial roads in Shanghai''s Pudong New Area. Its most distinctive feature is being "China''s first urban landscape avenue where greenery and sidewalks are wider than the vehicle lanes"—the north sidewalk alone is 44.5 meters wide, the south sidewalk 24.5 meters, with a total green landscape sidewalk area of 69 meters, more than three times that of an ordinary urban road. The avenue is lined with four rows of street trees, including evergreen camphor trees on the outer side and deciduous ginkgo and plane trees on the inner side, creating changing colors throughout the year and earning it the nickname "The Champs-Élysées of the East." Flanked by skyscrapers (Jin Mao Tower, SWFC, Shanghai Tower, Oriental Pearl) and low-rise financial street shops, the avenue is Shanghai''s most international city image display. Along the way, Century Park is a weekend leisure destination, while Century Square features a large musical fountain.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_07.png'),
  ('陆家嘴金融区', 7, 'Pudong Riverside Promenade (Dongchang Wharf to Taitongzhan Wharf Section)', '浦东滨江大道', '<p>The Pudong Riverside Promenade, located on the east bank of the Huangpu River in Pudong New Area, stretches approximately 2.5 kilometers from Dongchang Wharf in the west to Taitongzhan Wharf in the east, completed and opened in 1997. Comprising a water-friendly platform, sloped green landscape, semi-underground spaces, and landscape roads, it is hailed as the "Little Bund of Shanghai." Facing the historic Bund across the river, visitors can enjoy a panoramic view of the Puxi Bund''s "Expo of World Architecture" and Lujiazui''s modern skyscrapers (Oriental Pearl, Jin Mao, SWFC, Shanghai Tower), creating a magnificent dialogue between history and modernity. Lined with lush trees and blooming flowers, the promenade features over 20 themed sculptures, water-friendly viewing platforms, and cultural landmarks such as Chen Yi Square, the 1862 Shipyard Fashion Art Center, and the Shanghai Powerlong Art Museum. At night, the illuminated riverside becomes one of Shanghai''s most iconic destinations for evening strolls, jogging, cycling, and photography. The "1862 Shipyard," a former century-old shipyard converted into a fashion art center, regularly hosts fashion, art, and commercial events, becoming Lujiazui''s most artistic industrial-style new landmark.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_08.png'),
  ('陆家嘴金融区', 8, 'Shanghai Tower (Top of Shanghai Observation Hall)', '上海中心大厦（上海之巅）', '<p>Shanghai Tower, located at 501 Yincheng Middle Road, Pudong New Area, stands 632 meters tall with 127 above-ground floors and 5 basement levels. Fully completed and opened in 2015, it is the tallest building in China and the second tallest in the world, after the Burj Khalifa in Dubai. Designed by the American firm Gensler, the tower draws inspiration from DNA''s double-helix structure, with its form resembling a slowly twisting "dragon-like" curved surface. Its facade consists of nearly 20,000 curved glass panels that change color with the light. The complex integrates offices, hotels, commerce, and sightseeing, housing the J Hotel (floors 84-110, one of the world''s highest hotels), the 118F "Top of Shanghai" Observation Hall, the 126F "Damper Performance" installation, and the "Magic City Light" art exhibition. The "Top of Shanghai" observation hall on the 118th floor stands at 546 meters, making it the world''s highest indoor observation platform, offering 360-degree views. The 126F "Shanghai Eye"—a 1,000-ton tuned mass damper—is one of the world''s heaviest, blending technology and art seamlessly.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/lujiazui_financial_district_sa_09.png'),
  ('南外滩轻纺面料市场', 0, '', '市场入口大厅', '<p>The main entrance lobby of Nanwaitan Light Textile &amp; Fabric Market is the first stop on the journey into this "global bespoke center." Located at the front of the first floor of the main building at 399 Lujiabang Road, the high-ceilinged lobby reflects the "modern marketplace" identity that the market adopted after its 2005 upgrade. Multilingual signage in Chinese, English, Japanese, and Korean guides visitors to the different floors—ready-to-wear leather goods and the Kate &amp; Kevin studio on the first floor, suit tailoring and imported fabric on the second, qipao and traditional textiles on the third, and cashmere and miscellaneous goods on the fourth. A consultation counter staffed by multilingual shop assistants (English, French, German, Italian, and Spanish) assists foreign visitors with measuring, shipping, and alteration questions, while a "Shanghai Bespoke" wall displays stories of NBA players, the US water-polo team, and French flight attendants. During peak hours the lobby doubles as a meeting and bargaining space, with the scent of the Huangpu River mingling with silk—often called Shanghai''s most "alive" entry to international fashion.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_01.png'),
  ('南外滩轻纺面料市场', 1, '', '一楼-成衣与皮具区', '<p>The ready-to-wear and leather goods section occupies the west wing of the market''s first floor. With around 40 shops focused on off-the-rack apparel and accessories, it is the fastest-moving part of the market, ideal for visitors who want to buy and wear immediately. Racks and shelves display men''s and women''s suits, trench coats, leather jackets, blazers, shirts, dresses, evening gowns, and leather goods including cowhide, sheepskin, and crocodile-embossed handbags, briefcases, and belts. Most vendors sell by browsing and bargaining, with on-the-spot fitting and minor alterations; prices range from a few hundred to tens of thousands of RMB. Located next to the Kate &amp; Kevin studio and the lobby consultation counter, the section lets accompanying family or friends pick up a ready garment or a leather accessory while a tailor takes measurements. Many shop assistants can communicate in English about sizing and leather grades and help with packing and international shipping.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_02.png'),
  ('南外滩轻纺面料市场', 2, '', '一楼-Kate&Kevin定制工坊', '<p>The Kate &amp; Kevin bespoke studio sits in the east wing of the first floor, near the entrance lobby, and is one of the earliest studios in the market to operate fully in English with an end-to-end bespoke workflow. Sample gowns hang throughout the room—silk evening dresses, satin qipao, Xiangyunsha outerwear, lace bridal gowns, and cocktail dresses—while the walls display swatch cards of imported fabrics from Italy, the United Kingdom, and Japan. Founders Kate and Kevin follow a "one person, one pattern" draping method, beginning with British-style toile work on the form, then a basted fitting that respects the client''s shoulder, neck, bust, waist, and hip proportions, and finishing with hand-stitched hems, pankou knots, and concealed zippers. The studio specializes in evening gowns, qipao, and bridal collections, as well as fusion pieces that combine Chinese standing collars with Western silhouettes. Lead time is usually 7–14 days, and appointments are recommended in peak seasons (March, May, and September–October). In partnership with the Huangpu Post Office counter on the fourth floor, finished garments can be shipped directly to more than 170 countries and regions.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_03.png'),
  ('南外滩轻纺面料市场', 3, '', '二楼-西装定制核心区', '<p>The second floor is the heart of Nanwaitan Light Textile &amp; Fabric Market and the densest cluster of shops—more than 60 tailors dedicated to men''s suits, shirts, trench coats, and overcoats line both sides of the atrium corridor. It is the area that drives most of the "Shanghai Bespoke" reputation on overseas social media. Most shops follow a "front shop, back factory" model: the front displays wool, cashmere, and blend fabric swatches and sample garments, while the back houses a team of cutters, machinists, and pressers who produce the basted, half-finished, and finished garments. The standard workflow runs from fabric selection to measurement, basted fitting, second fitting, and finished garment, with a 7–14-day lead time that can be compressed to 3–4 days for rush orders. Many shop assistants speak English—and often French, Spanish, or Japanese—and accept remote measurement by photo or video. Stories of international clients such as NBA star Dirk Nowitzki and the US water-polo team are often posted on the walls and on social media, helping first-time visitors identify the silhouette that best suits them.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_04.png'),
  ('南外滩轻纺面料市场', 4, '', '二楼-进口面料坊', '<p>The imported fabric section sits on the inner side of the 2F east wing, with about 15–20 shops and counters dedicated to premium imported fabrics. It shares foot traffic with the core suit-tailoring area but occupies a higher-end niche. This is where fabric connoisseurs browse: brand-name books from Italy''s Loro Piana, Vitale Barberis Canonico, Zegna, and Reda, the UK''s Holland &amp; Sherry and Fox Brothers, and Japan''s Dormeuil line the shelves, alongside Chinese luxury textiles such as Xiangyunsha, Song brocade, and Zhang velvet. Shop owners typically speak English and Japanese, helping customers understand yarn counts (Super 130s/150s/180s), weave structures (plain, twill, herringbone), cloth weight, and seasonal use, then recommending combinations to match any budget. The section rarely produces garments itself, but it works hand-in-glove with the core tailoring shops and half-finished garment workshops on the same floor—a selection-to-basted-garment turnaround of 3–5 days is common.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_05.png'),
  ('南外滩轻纺面料市场', 5, '', '三楼-旗袍与中式服装区', '<p>The central atrium of the third floor is the most distinctively "Eastern" section of the market, gathering around 30 shops that specialize in qipao, changshan, magua, and traditional Chinese wedding attire. Its clientele is strikingly international—French, Singaporean, and Malaysian brides, Chinese-diaspora communities in the US and Canada ordering festival gowns, and Russian and Ukrainian customers ordering bridesmaid qipao all leave their mark here. Fabrics are dominated by silk crepe de Chine, brocade, Xiangyunsha, Song brocade, Zhang velvet, and embroidered cloths, with both fully hand-stitched and hybrid hand-and-machine options available. Mandarin collar height, pankou design, slit position, and sleeve length can all be tailored to the client''s figure and taste. Lead time runs 7–14 days, with 3–5-day rush service available; during Chinese New Year and the seventh lunar month, shops often require 1–2 months of advance booking. Finished qipao can be shipped abroad directly from the Huangpu Post Office counter on the fourth floor.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_06.png'),
  ('南外滩轻纺面料市场', 6, '', '三楼-传统面料零售区', '<p>The traditional fabric retail area runs along the east and south wings of the third floor, with 30–40 counters selling fabric by the metre in a "cut and carry" model. Its main customers are local qipao enthusiasts, independent designers, theatrical costume studios, and DIY buyers. The selection covers everything from basics to niche pieces: silk satin crepe, crepe de chine, organza, chiffon, and habotai; cotton and linen such as washed cotton, ramie, and flax; wool ranging from coarse to worsted fancy tweeds; synthetics and blends suited to school projects or stage costumes; and distinctive textiles including blue calico, batik, tie-dye, ethnic brocade, and Peking opera costume cloth. Counters accept both small cut orders (from 0.5 m) and wholesale volumes, which is convenient for individual buyers. Many can recommend the right fabric width and cutting plan for a client''s figure and can arrange shipping or hand-carry packaging. This is the most upstream "raw material window" of the Shanghai bespoke industry chain.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_07.png'),
  ('南外滩轻纺面料市场', 7, '', '四楼-羊绒与杂项区', '<p>The fourth floor is the top level of the market, with 25–35 shops dedicated to cashmere and complementary accessories; it is at its liveliest during autumn and winter. Visitors can find Inner Mongolia-, Xinjiang-, and Qinghai-sourced pure cashmere yarn, cashmere scarves and shawls, and bespoke-knitted and custom-dyed cashmere sweaters, cardigans, and double-faced cashmere overcoats. The "miscellaneous" range covers sheepskin gloves, belts, silk scarves, buttons, pankou knots, zippers, lining cloth, brooches, tie clips, and cuff links, letting customers put together an entire outfit on the same floor. Many shops offer semi-bespoke service—adjusting collar, sleeve, and body length on ready patterns with a 2–3-day turnaround. The price ladder is clear: from RMB 300 plain cashmere sweaters to over RMB 10,000 premium overcoats. It is the floor that most clearly showcases the value-for-money side of "Shanghai Bespoke."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_08.png'),
  ('南外滩轻纺面料市场', 8, '', '黄浦邮政国际寄送服务台', '<p>The Huangpu Post Office international shipping counter sits near the escalator on the fourth floor. Established in 2025 under the coordination of the Huangpu District Commerce Commission, it is the temporary service point that completes the "fit on arrival, ship to the world on departure" loop that has become a Nanwaitan signature. The counter offers international EMS, international small packets, registered mail, and air/sea-surface services covering more than 170 countries and regions. On-site workflow: customers present the finished garment, the bespoke order receipt, and valid ID; staff cushion the garment in shockproof paper, reinforce the four corners, weigh and price the parcel, and print the waybill—two bespoke shirts weighing 0.49 kg to Paris, for example, take 5–7 working days at around RMB 260. Beyond shipping, the counter plans a "Nanwaitan Bespoke" themed post office, cultural postcards, and limited-edition philatelic products, making it one of Shanghai''s most representative "national-trend meets international courier" experience points.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/south_bund_fabric_market_commonly_known_as_dongjiadu_fabric_market_sa_09.png'),
  ('上海博物馆', 0, '', '中国古代青铜馆', '<p>The Ancient Chinese Bronze Gallery, on the east wing of the first floor of the Shanghai Museum''s People''s Square building, is one of the most academically significant permanent exhibitions in the museum''s "half-of-China" collection. Covering about 1,200 square meters, it is organized into seven sections—Emergence, Growth, Apex, Transition, and Renewal—together with two thematic units on bronzes from peripheral regions and on smelting and casting techniques. Highlights include Erlitou-culture bronze jue vessels, Shang-dynasty taotie-pattern square ding, Western Zhou masterpieces such as Da Yu Ding and Mao Gong Ding, the Spring and Autumn Lotus and Crane Square Hu, and a replica of the Marquis Yi of Zeng bell set alongside Chu-style rising ding. The route reveals ritual, political, and metallurgical dimensions of early Chinese bronze civilization through vessel typology, inscriptions, and craftsmanship.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_01.png'),
  ('上海博物馆', 1, '', '中国古代雕塑馆', '<p>The Ancient Chinese Sculpture Gallery occupies the west wing of the first floor, mirroring the Bronze Gallery. It covers about 640 square meters and is divided into four periods—Warring States to Qin–Han, Wei–Jin through the Sui, Tang–Five Dynasties, and Song–Yuan—with roughly 120 works, of which about 80% are Buddhist statues. Early sections lead with Huo Qubing''s tomb reliefs, replicas of the Qin terracotta warriors, and Han pottery figures. The middle period is anchored by Northern dynasties sculptures from Yungang, Longmen, Maijishan, and Dunhuang, alongside white-marble Buddhas from Quyang in Hebei and Liang-dynasty pieces from Wanfo Temple in Sichuan. The Tang–Five Dynasties unit gathers Chang''an-style pieces, Dunhuang painted sculptures, and the Amitabha from the Leifeng Pagoda crypt. The Song–Yuan section pivots to Jinci painted sculptures, Lingyan Temple luohans, and Tibetan-Buddhist statues. A parallel storyline—icons, donors, guardian figures, and tomb sculpture—traces the transformation of Chinese sculpture from ritual object to devotional image.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_02.png'),
  ('上海博物馆', 2, '', '中国古代陶瓷馆', '<p>The Ancient Chinese Ceramics Gallery occupies the central area of the second floor. Covering about 1,300 square meters with more than 500 pieces, it is one of the most complete and large-scale surveys of Chinese ceramic history in the museum''s collection. Seven chronological sections—Neolithic painted pottery, Shang–Zhou proto-porcelain, Han–Jin and Northern–Southern dynasties, Tang sancai and early celadon, Song dynasty''s six great kiln systems (Ru, Guan, Ge, Jun, Ding, and Yue, Longquan, Yaozhou, Cizhou), Yuan–Ming–Qing Jingdezhen blue-and-white and monochrome glazes, and Ming–Qing regional kilns (Yixing zisha, Dehua blanc de Chine, Shiwan)—trace the full arc. Key objects include Majiayao painted pottery basins, Shang proto-porcelain zun, a Northern Qi white-splash-on-green long-neck vase, Tang sancai camel with musicians, a Ru ware sky-blue narcissus basin, a Yuan blue-and-white peony jar, a Ming Yongle sweet-white carved prunus vase, and a Kangxi famille-rose bowl. Five-dimensional labels (period, type, kiln, technique, motif) make the room a complete index for the study of Chinese ceramics.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_03.png'),
  ('上海博物馆', 3, '', '中国历代书法馆', '<p>The Chinese Calligraphy Gallery is on the east wing of the third floor, covering about 600 square meters. About 60 masterworks are arranged in six chronological sections—seal and clerical scripts, Jin–Tang calligraphy, Song, Yuan, Ming, and Qing. Highlights include Shang oracle-bone and Western Zhou bronze rubbings, the best-preserved fragments of the Chunhuage Tie, a Tang copy of Wang Xizhi''s Shangyu Tie, Huai Su''s Bitter Bamboo Shoot Tie, Emperor Huizong''s Slender-Gold Thousand-Character Classic, Su Shi''s memorial draft for Huang Jidao, Huang Tingjian''s cursive Lienpo and Lin Xiangru Biographies, Zhao Mengfu''s Danba Stele, works by Zhu Yunming, Wen Zhengming, Dong Qichang, Wang Duo, and Fu Shan, and letters and hand scrolls from the "Two Wangs" lineage. Standing desks with high-resolution digital comparison panels allow visitors to study brushwork, composition, and ink tonality.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_04.png'),
  ('上海博物馆', 4, '', '中国历代绘画馆', '<p>The Chinese Painting Gallery occupies the west wing of the third floor, opposite the Calligraphy Gallery. Covering about 1,200 square meters and displaying more than 120 works from the Tang dynasty to modern times, it is one of the largest permanent ancient painting exhibitions on the Chinese mainland. Seven chronological sections—Tang–Song, Yuan, early-to-mid Ming, late Ming to early Qing, mid Qing, late Qing, plus the dedicated "Liangtu Xuan" gallery—trace the evolution of Chinese painting from blue-and-green landscape to literati xieyi. Treasures include Sun Wei''s High Recluse scroll (the only surviving handscroll of its theme), Emperor Huizong''s Willows, Crows, and Reed Geese, Liang Kai''s Eight Eminent Monks, Wang Shen''s Misty Rivers and Layered Peaks, Zhao Mengfu''s Horses at the Autumn Outskirts, Ni Zan''s Six Gentlemen, masterworks by the Four Masters of Wu (Shen Zhou, Wen Zhengming, Tang Yin, Qiu Ying), Dong Qichang''s Eight Views of Yan and Wu album, the Four Wangs, Four Monks, Jinling and Yangzhou schools, and Ren Bonian and Xu Gu of the Shanghai school. Low-illumination cold lighting and UV-filtering vitrines protect silk and paper surfaces.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_05.png'),
  ('上海博物馆', 5, '', '中国历代玺印馆', '<p>The Chinese Seals Gallery is at the center of the third floor and is the first dedicated museum of Chinese seal engraving in China, covering 380 square meters with more than 500 pieces. Five sections follow the art historical line: early archaic seals (Shang–Zhou through Warring States bronze official and private seals, nose and altar knobs); the Qin–Han codification (Qin "field-grid" seals, Han seal script, jade seals and bird-worm script); Tang–Song–Jin–Yuan new styles (regular-script seals, hand-pressed marks, studio seals); the rise of literati seal carving in Ming–Qing (Wen Peng, He Zhen, the Wan and Zhe schools, Deng Shiru, Wu Rangzhi, Zhao Zhiqian, Wu Changshuo and their lineages); and Ming–Qing seal materials and finial carving (Qingtian, Shoushan, Changhua, Balin stones with full-round and relief knobs). A closing section on "seal catalogues and seal studies" displays the Shizhong Shanfang Yinju, Xueshantang Seal Catalogue, and Xiling Bajia catalogue, linking original seals with their bibliographic counterparts.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_06.png'),
  ('上海博物馆', 6, '', '中国古代玉器馆', '<p>The Ancient Chinese Jades Gallery is on the fourth floor, covering 500 square meters. About 300 jades from the Neolithic to the Qing dynasty are arranged in six units—prehistoric, Xia–Shang–Western Zhou, Spring and Autumn–Warring States, Han–Jin, Tang–Song–Liao–Jin, and Yuan–Ming–Qing. Highlights include a Hongshan-culture jade pig-dragon, Lingjiatan-culture jade eagle and jade plate, Liangzhu cong with a deity-and-beast mask (one of the museum''s heaviest), Shang dynasty birds and blades, Fu Hao–style phoenix and figures, Western Zhou pendant sets, Spring and Autumn coiled-dragon bi, Warring States dragon pendants and multi-segment articulated chains, a complete Han dynasty gold-wire jade burial suit and jade dancers, Tang–Song flying apsaras, Liao–Jin "Spring Water" and "Autumn Mountain" jades, Ming–Qing Zigang plaques, Mughal-influenced "Hindustan" jades, and Qianlong-era inscribed jade mountain-sculptures. The storyline—ritual object, ornament, mortuary piece, scholar''s implement, display piece—traces jade''s cultural trajectory from divine to royal to literari aesthetic.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_07.png'),
  ('上海博物馆', 7, '', '中国历代钱币馆', '<p>The Chinese Coins Gallery is on the fourth floor and covers 740 square meters, displaying more than 3,300 objects—one of the largest permanent numismatic exhibitions in China. The chronological storyline runs from pre-Qin cowries, spade, knife, and round coins; Qin–Han half-tael and wuzhu; Tang Kaiyuan Tongbao and feiqian; Song money drafts, Jiaozi, silver ingots, and bronze–iron coinage in parallel; Yuan paper money and silver ingots; Ming–Qing baochao, sycee, and machine-struck copper coins; to modern machine-struck silver dollars, copper cents, and currency from red-base regions—tracing money from commodity to metal, from metal to paper, and from hand to machine striking. Two thematic rooms: the "Shi Jiagan Numismatic Room" displays rare Chinese antique and machine-struck coins donated by the modern collector Shi Jiagan; the "Du Weishan and Tan Duanyan Central Asian Coins Room" displays Sogdian, Kushan, Sasanian, and Arabo-Persian coins from the Silk Road donated by the Australian-based scholar Du Weishan and his wife, reflecting East–West monetary exchange along the Silk Road.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_08.png'),
  ('上海博物馆', 8, '', '中国明清家具馆', '<p>The Ming–Qing Chinese Furniture Gallery is in the west wing of the fourth floor, covering 700 square meters with more than 100 masterpieces. The route divides into two stylistic threads: Ming furniture, in huanghuali, zitan, and tieli, prized for spare forms, rounded lines, and precise proportions—exemplified by a huanghuali four-flush official''s cap armchair, a huanghuali flat-top table with insert shoulders, a zitan horseshoe-back armchair, and a zitan large painting table; and Qing furniture, in zitan and hongmu, marked by lavish carving, auspicious motifs, and grandeur—exemplars include a Qianlong-period zitan throne with Western lotus carving, a mid-Qing hongmu carved screen, and mother-of-pearl and marble-inlaid long tables and Eight Immortals tables. Two recreated interiors—an Ming reception hall (centered on long table, Eight Immortals table, armchairs, and flower stands) and a Qing scholar''s studio (painting table, horseshoe-back chair, bookcase, and official leather box)—help visitors read furniture within the ritual and daily grammar of traditional Chinese homes. A wall of mortise-and-tenon detail diagrams shows swallowtail, hugging-shoulder, dumpling-angle, insert-shoulder, and through-shoulder joints.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_09.png'),
  ('上海博物馆', 9, '', '解说词-中国少数民族工艺馆', '<p>The Chinese Ethnic Minorities Craft Gallery is on the fourth floor''s east wing, adjacent to the Jades Gallery. With more than 700 square meters and nearly 600 objects, it is the most culturally diverse permanent gallery in the People''s Square museum. Eight craft sections—ethnic costume (Mongolian robe, Tibetan chuba, Yi pleated skirt, Miao silver headdress, Uyghur doppa); dyeing, weaving, and embroidery (batik, tie-dye, embroidery, brocade—Miao embroidery, Dong brocade, Zhuang brocade, Dai brocade, Tujia "Xilankapu", Li brocade, Tibetan pulu); metalwork (Miao silver, Yi silver, Tibetan Buddhist ritual objects and butter lamps, Dai silver ewers, Mongolian gold and silver); carvings (Wa woodcarving, Tibetan carved doors and sutra blocks, Miao wooden masks, Tajik stone carving); ceramics (Dai slow-wheel pottery, Tibetan "ka" kiln ware, Kazakh glazed pottery); lacquerware (Yi lacquer, Tibetan gilt-and-painted, Miao lacquered leather armor); rattan and bamboo weaving (Li rattan, Dai bamboo, Miao baskets, Yi back-baskets); and mask art (Tibetan opera masks, Nuo masks, Yi bimo masks, Miao Lusheng festival masks)—represent the crafts of ethnic regions across all Chinese provinces, autonomous regions, and municipalities. The gallery emphasizes the context of craft, community, festival, and daily life, providing a visual model for understanding the "diversity in unity" of Chinese culture.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_museum_sa_10.png'),
  ('上海迪士尼度假区', 0, '', '米奇大街', '<p>Located at the very front of the park''s main entrance, Mickey Avenue is the first themed street every visitor walks through upon entering. The street draws design inspiration from the stories of Mickey, Minnie, Donald, Goofy, Pluto, and other classic Disney characters. Both sides feature retail and dining facilities including the Old Station Store, Sweethearts Confectionery, and Mickey &amp; Pals Market Café. The avenue replaces the nearly 60-year tradition of "Main Street, U.S.A." found at other Disney parks worldwide, incorporating Chinese elements—building colors and decorative patterns reference Shanghai''s Bund and Old City styles. It is the best viewing spot for the Mickey''s Storybook Express parade and a prime location for photos with Duffy, ShellieMay, StellaLou, Gelatoni, and other characters.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_01.png'),
  ('上海迪士尼度假区', 1, '', '奇想花园', '<p>Garden of Imagination is situated in the north-central part of the park, with the Enchanted Storybook Castle as its visual centerpiece. Multiple classic attractions are arranged around the castle. The area''s signature facility, the Fantasia Carousel, was handcrafted by Chinese artisans, blending 72 colors to become one of the most exquisite carousels in any Disney park worldwide. The area also features Dumbo the Flying Elephant outdoors, the "Garden of the Twelve Friends" (Disney characters interpreting Chinese zodiac mural walls), the Marvel Heroes Headquarters indoor interactive experience (including an Iron Man transformation), and a classic photo spot with Mickey. The garden''s design extensively uses Chinese garden elements—pavilions, rockeries, willow trees, and lotus ponds—making it the most stroll-and-photo-friendly area in the park.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_02.png'),
  ('上海迪士尼度假区', 2, '', '探险岛', '<p>Adventure Isle is located in the southeast of the park, themed around ancient jungle tribe exploration. The area''s core landmark is "Roaring Mountain"—an artificial rock formation through which run the river rapids ride and the flight experience theater. The signature attraction, "Soaring Over the Horizon," is one of the longest-queued rides in the park. Visitors board suspended flying vehicles and soar over global landmark landscapes on a giant dome screen (height requirement ≥102cm). Other attractions include "Roaring Rapids" (outdoor white-water rafting, height ≥107cm) and "Camp Discovery" (rope challenge courses and outdoor exploration trails). The area''s design draws from a blend of Pacific Island and South American jungle civilizations, enhanced with mist and water fog effects, making it one of the park''s most immersive themed zones.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_03.png'),
  ('上海迪士尼度假区', 3, '', '宝藏湾', '<p>Treasure Cove is located in the northeast of the park and is the first pirate-themed area in any Disney park worldwide. Based on the "Pirates of the Caribbean" film franchise, the area recreates an 18th-century Caribbean harbor town—cobblestone streets, wooden docks, rundown taverns, and pirate ship masts. The signature attraction, "Pirates of the Caribbean: Battle for the Sunken Treasure," is the park''s most technologically advanced boat ride. Visitors journey through underwater shipwrecks, pirate battles, and volcanic eruptions, with projection and physical sets seamlessly integrated. Other attractions include "Siren''s Revenge" (ship boarding experience) and "Explorer Canoes" (paddling through the waterways of Treasure Cove and Adventure Isle). The area''s show, "Eye of the Storm: Captain Jack''s Stunt Spectacular," runs about 30 minutes and is one of the park''s most popular live performances.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_04.png'),
  ('上海迪士尼度假区', 4, '', '梦幻世界', '<p>Fantasyland is located in the northern part of the park and is the themed area with the most attractions (9), with classic Disney animated fairy tales as its core narrative. The area''s core landmark, the "Enchanted Storybook Castle," is the tallest and largest Disney castle in the world, with its spire adorned with Chinese auspicious clouds, peonies, and magnolia elements—making it the park''s most popular photo spot. Signature attractions include Seven Dwarfs Mine Train (family roller coaster, height ≥97cm), Peter Pan''s Flight (indoor suspended flight), The Many Adventures of Winnie the Pooh (indoor ride), Voyage to the Crystal Grotto (outdoor water ride), Alice in Wonderland Maze (outdoor interactive maze), and more. The castle also houses the "Once Upon a Time" Snow White interactive experience and the "Frozen: A Musical Spectacular" show (about 20 minutes).</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_05.png'),
  ('上海迪士尼度假区', 5, '', '明日世界', '<p>Tomorrowland is located in the northwest of the park, themed around futuristic technology and sci-fi exploration. The area''s architecture is full of streamlined metallic surfaces and neon lighting effects, creating a "cyberpunk" futuristic city atmosphere. The signature attraction, "TRON Lightcycle Power Run Presented by Chevrolet," is an indoor high-speed motorcycle-style roller coaster (height ≥122cm). Riders straddle glowing lightcycles and race through light-and-shadow tunnels—making it one of the most thrilling coasters in any Disney park worldwide. Other attractions include "Buzz Lightyear Planet Rescue" (indoor interactive shooting), "Jet Packs" (outdoor spinning flight, height ≥122cm), and "Create: Chevrolet Digital Challenge" (interactive future driving experience). The area also regularly hosts "Avengers Training Initiative" shows and "E-Club" electronic music parties.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_06.png'),
  ('上海迪士尼度假区', 6, '', '玩具总动员乐园', '<p>Toy Story Land is located in the northwest of the park, adjacent to Tomorrowland. It opened on April 26, 2018, as Shanghai Disneyland''s first expanded themed area. The design is based on the "Toy Story" film universe—upon entering, visitors are "shrunk" to toy size and enter protagonist Andy''s backyard, where everyday objects like building blocks, Slinky Dog, paper kites, and dominoes become super-sized installations. Signature attractions include Rex''s Racer (U-shaped track racing, height ≥120cm), Slinky Dog Spin (outdoor spinning chase), and Woody''s Round-Up (western wagon ride, height ≥81cm). The area is brightly colored with a relaxed pace, making it the most family-friendly and young-children-friendly themed area in the park.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_07.png'),
  ('上海迪士尼度假区', 7, '', '疯狂动物城', '<p>Zootopia is located in the eastern part of the park, adjacent to Treasure Cove. It officially opened on December 20, 2023, as the world''s first "Zootopia" themed area and the eighth themed area of Shanghai Disneyland. The area faithfully recreates the urban scenes of Zootopia from the film—animal districts of different sizes, the train system, neon signs, and City Hall. The signature attraction, "Zootopia: Hot Pursuit," is the park''s newest high-tech immersive ride. Throughout the area, interactive installations and photo spots featuring Nick, Judy, Flash, and other film characters can be found. On March 10, 2023, the red panda "Mei Mei" made her global debut here. In November 2024, the area received the Themed Entertainment Association (TEA) 2025 "Outstanding Achievement Award for a Theme Park Land."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_08.png'),
  ('上海迪士尼度假区', 8, '', '迪士尼小镇', '<p>Disneytown is located south of the main entrance of Shanghai Disneyland, outside the park walls. It is an independent commercial and entertainment area within the resort—no park ticket required to enter. Covering approximately 46,000 square meters, the town is divided into three zones: "Town Center," "Broadway Plaza," and "Broadway Avenue." It features globally renowned dining brands (such as The Cheesecake Factory, The BOATHOUSE, and Element Table), the official Disney Store (one of the world''s largest Disney flagship stores), Dayin Bookstore, LEGO Brand Store, and other retail shops. The "Walt Disney Grand Theatre" within the town stages the Broadway musical "The Lion King" in Chinese (separate ticket required). The town also regularly hosts seasonal markets, outdoor performances, and light installations, making it a popular destination for spending a half-day outside the park.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_09.png'),
  ('上海迪士尼度假区', 9, '', '星愿公园', '<p>Wishing Star Park is located on the west side of the Shanghai Disney Resort, built around the 400,000-square-meter "Wishing Star Lake." It is a free-entry open park independent of the park walls within the resort. The park features an approximately 2.5 km lakeside trail, with waterfront platforms, gardens, a children''s playground, picnic lawns, and multiple photo spots along the way. The park is named after the Disney animation "Mulan" song "When You Wish Upon a Star." At the center of the lake stands a giant light installation called "Wishing Star," which illuminates at night and reflects on the water—making it one of the resort''s iconic night views. The park also offers bicycle rentals (tandem/four-person bikes), kayaking experiences, and seasonal flower exhibitions, making it an ideal choice for families and runners to spend time outside the park.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/shanghai_disney_resort_sa_10.png'),
  ('上海外滩', 0, 'Shiliupu Wharf', '十六铺码头', '<p>Once Shanghai''s largest inland passenger ferry terminal, now transformed into a waterfront complex integrating sightseeing, leisure, and commerce.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_01.png'),
  ('上海外滩', 1, 'Bund 18', '外滩十八号', '<p>Originally the Chartered Bank Building, completed in 1923, now a high-end art, dining, and retail complex on the Bund.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_02.png'),
  ('上海外滩', 2, 'Asia Building (Bund No. 1)', '亚细亚大楼（外滩一号）', '<p>Known as the "First Building of the Bund," completed in 1913, blending Baroque and Neoclassical styles; currently the headquarters of China Pacific Insurance.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_03.png'),
  ('上海外滩', 3, '上海总会（华尔道夫酒店） / Shanghai Club (Waldorf Astoria Shanghai on the Bund)', '上海总会（华尔道夫酒店）', '<p>A British Renaissance-style gentlemen''s club built in 1910, home to the legendary 34-meter bar; now the Waldorf Astoria hotel.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_04.png'),
  ('上海外滩', 4, 'Former HSBC Building', '原汇丰银行大楼', '<p>Completed in 1925, widely regarded as the most beautiful building on the Bund; a masterpiece of Neoclassical architecture, now the headquarters of SPD Bank.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_05.png'),
  ('上海外滩', 5, '海关大楼 / Customs House (Shanghai)', '海关大楼', '<p>Rebuilt in 1927 in Greek Neoclassical style; its clock tower, modeled after the Palace of Westminster clock, was once known as "Asia''s First Clock."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_06.png'),
  ('上海外滩', 6, '和平饭店 / Peace Hotel (Fairmont Peace Hotel)', '和平饭店', '<p>An Art Deco landmark built in 1929, funded by British-Jewish tycoon Victor Sassoon; once the tallest building in the Far East, now a Fairmont luxury hotel.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_07.png'),
  ('上海外滩', 7, '陈毅广场与陈毅铜像 / Chen Yi Square and Bronze Statue of Chen Yi', '陈毅广场与陈毅铜像', '<p>A core waterfront plaza on the Bund featuring a 9-meter-tall bronze statue of Chen Yi, the first Mayor of Shanghai, and an important civic memorial landmark.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_08.png'),
  ('上海外滩', 8, '外滩牛 / Bund Bull (Shanghai Financial Bull)', '外滩牛', '<p>A red bronze bull sculpture unveiled during Expo 2010 Shanghai, created by Arturo Di Modica — the same artist behind the Wall Street Charging Bull — symbolizing the prosperity and strength of Shanghai as an international financial center.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_09.png'),
  ('上海外滩', 9, '上海市人民英雄纪念塔 / Shanghai People''s Heroes Memorial Tower', '上海市人民英雄纪念塔', '<p>Standing in Huangpu Park at the confluence of the Huangpu River and Suzhou Creek, three 60-meter granite gun-shaped towers commemorate the people''s heroes who sacrificed their lives since the Opium War.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_10.png'),
  ('上海外滩', 10, '外白渡桥 / Waibaidu Bridge (Garden Bridge of Shanghai)', '外白渡桥', '<p>China''s first all-steel riveted bridge, built in 1907, spanning the mouth of Suzhou Creek where it flows into the Huangpu River — one of Shanghai''s most iconic century-old bridges.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_11.png'),
  ('上海外滩', 11, '外滩源 / The Origin of the Bund (Waitanyuan)', '外滩源', '<p>The "source" of the Bund, home to its earliest surviving buildings, centered on the former British Consulate — a fusion of heritage architecture with contemporary art and commercial spaces.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/the_bund_shanghai_sa_12.png'),
  ('苏州河十二国色', 0, '高陵集市（鹅黄色） / Gaoling Market (Goose-yellow)', '高陵集市（鹅黄色）', '<p>The most vibrant Shikumen-style community market in Putuo''s Zhenru area, paired with the "goose-yellow" hue in the "Twelve Classical Colors of Suzhou Creek," echoing a century of Shanghai street life.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_01.png'),
  ('苏州河十二国色', 1, '曹杨新村（月白色） / Caoyang New Village (Moon-white)', '曹杨新村（月白色）', '<p>New China''s first workers'' residential community, paired with the "moon-white" hue in the "Twelve Classical Colors of Suzhou Creek," embodying the collective memory of Shanghai''s working class.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_02.png'),
  ('苏州河十二国色', 2, '玉佛寺（朱红色） / Jade Buddha Temple (Vermilion)', '玉佛寺（朱红色）', '<p>A celebrated Chan Buddhist temple in Shanghai housing the treasured seated jade Sakyamuni statue, paired with the "vermilion" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_03.png'),
  ('苏州河十二国色', 3, 'M50创意园（翠绿色） / M50 Creative Park (Emerald-green)', 'M50创意园（翠绿色）', '<p>A landmark industrial-heritage art district on Suzhou Creek and one of Asia''s most renowned creative clusters, paired with the "emerald-green" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_04.png'),
  ('苏州河十二国色', 4, '雾苑堂茶室（天青色） / Wuyuantang Tea House (Sky-blue-grey)', '雾苑堂茶室（天青色）', '<p>A Song-dynasty-inspired tea house set in tranquility along Suzhou Creek, paired with the "sky-blue-grey" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_05.png'),
  ('苏州河十二国色', 5, '竹丝编非遗体验馆（竹青色） / Bamboo Silk Weaving Intangible Heritage Hall (Bamboo-green)', '竹丝编非遗体验馆（竹青色）', '<p>A showcase and hands-on space for Putuo''s district-level intangible cultural heritage of bamboo silk weaving, paired with the "bamboo-green" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_06.png'),
  ('苏州河十二国色', 6, '顾正红纪念馆（玄采色） / Gu Zhenghong Memorial Hall (Mystic-black)', '顾正红纪念馆（玄采色）', '<p>The memorial hall for Gu Zhenghong, a pioneer of the May 30th Movement, designated as a Shanghai Patriotism Education Base, paired with the "mystic-black" hue.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_07.png'),
  ('苏州河十二国色', 7, '苏州河工业文明展示馆（丁香色） / Suzhou Creek Industrial Civilization Exhibition Hall (Lilac)', '苏州河工业文明展示馆（丁香色）', '<p>A thematic exhibition hall chronicling a century of industrial heritage along Suzhou Creek, housed in the former Shanghai No. 1 Optical Factory, paired with the "lilac" hue.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_08.png'),
  ('苏州河十二国色', 8, 'Banma Suhe Park (Cobalt-blue)', '半马苏河公园（钴蓝色）', '<p>A signature waterfront greenway along Suzhou Creek, the highlight of the 21-km "Half Marathon Suzhou Creek" riverside corridor, paired with the "cobalt-blue" hue.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_09.png'),
  ('苏州河十二国色', 9, '百禧公园（紫棠色） / Baixi Park (Purple-tang)', '百禧公园（紫棠色）', '<p>An 880-meter three-dimensional community park converted from an abandoned railway, paired with the "purple-tang" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_10.png'),
  ('苏州河十二国色', 10, '鸿寿坊（琥珀色） / Hongshoufang (Amber)', '鸿寿坊（琥珀色）', '<p>A Shikumen commercial block converted from the nearly century-old Xikang Market, paired with the "amber" hue in the "Twelve Classical Colors of Suzhou Creek," blending street life and Shanghai-style refinement.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_creek_twelve_nations_colors_sa_11.png'),
  ('苏州河十二国色', 11, '创享塔（木槿色） / The X Tower Chuangxiangta (Hibiscus)', '创享塔（木槿色）', '<p>A creative office park converted from a 1938 textile mill on the Suzhou Creek waterfront, paired with the "hibiscus" hue in the "Twelve Classical Colors of Suzhou Creek."</p>', ''),
  ('武康路', 0, '武康路 1 号）', '武康大楼（原诺曼底公寓', '<p>Located at the five-way intersection of Huaihai Middle Road and Wukang Road, Wukang Mansion was designed by Hungarian-Slovak architect László Hudec in 1924. Originally called "Normandie Apartments" and renamed Wukang Mansion in 1953, it is one of Shanghai''s earliest modern high-rise apartment buildings. The huge "ship-shaped" wedge-shaped volume inserts itself into the intersection; with one basement and eight above-ground floors, the continuous outer corridors and rounded corner stretch from Huaihai Middle Road into the depths of Wukang Road. It is Shanghai''s only surviving 1920s "ship-shaped" apartment. The ground floor hosts arcades and shops — coffee shops, light dining, creative stores, and a small documentary exhibition. After repeated renovations, the contrast between granolithic and red-brick façades is striking, making it the best viewing point for the plane-tree-lined Huaihai Middle Road streetscape and the famed "First Turn in Shanghai."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_01.jpg'),
  ('武康路', 1, 'Former Residence of Soong Ching-ling (No. 393 Wukang Road)', '武康路 · 宋庆龄故居', '<p>Located at No. 393 Wukang Road, the residence was moved into by Soong Ching-ling in 1948 and remained her home until her death in 1981 — her longest-tenured Shanghai residence and the place where she received the most Chinese and foreign guests. After Shanghai''s liberation in 1949 it also served as a state guest parlor. Converted into a memorial museum after her death in 1981, the residence officially opened to the public in 1982. The collection holds over 15,000 items — photographs with Sun Yat-sen, Chongqing-era wartime clothing, post-1949 diplomatic gifts, late-life manuscripts, and personal effects. The main building is a 1920s Western garden residence; the front and rear gardens remain open and simple, with the dining room and parlor preserved as Soong Ching-ling kept them — one of Shanghai''s most important "celebrity residence + state parlor" complexes.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_02.jpg'),
  ('武康路', 2, '武康路 393 弄黄兴故居老房子艺术中心', '黄兴故居', '<p>Located in Lane 393 of Wukang Road, this was Shanghai residence of 1911 Revolution leader Huang Xing during 1913—1916, commonly known as "Chongde Lou." When Huang Xing passed away in Shanghai in 1916, Sun Yat-sen inscribed the characters "Xingjian" (Vigorous Action) in his memory. Listed as a Shanghai Municipal Cultural Relic in 1992, since 2010 the building has been operated as the "Old-House Art Center," co-curated by Shanghai Dramatic Arts Centre and Shanghai Jingju Theatre. It regularly hosts small art exhibitions, drama salons, Peking-Chinese opera chamber concerts, and creative markets. The building is a three-bay two-story brick-and-timber Western-style residence with gray-brick walls and simple cornices — a typical early-Republic Shanghai high-end residence forming a "dual-landmark" pairing with the Soong Ching-ling residence to its south.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_03.jpg'),
  ('武康路', 3, 'Former Residence of Zhou Xuan (No. 1, Lane 391, Wukang Road)', '武康路 · 周璇旧居', '<p>Located at No. 1, Lane 391 of Wukang Road, this is one of 1930s—40s "Golden Voice" singer Zhou Xuan''s several Shanghai residences. The building is a 1920s three-story brick-and-timber Western-style residence with cream-yellow walls, a corner balcony on the second floor, and dormer windows on the third — a simple and understated façade. The lane is a private "new-style lilong," used by Zhou Xuan''s family and peers in the entertainment world. After Zhou Xuan passed away in 1957 the building reverted to private ownership and has never been publicly opened; it remains a private plot. Visitors can view the façade and take photos from the lane entrance, but the interior is not accessible. It is best combined with other celebrity residences along Wukang Road for a "Searching for Socialites Beneath the Plane Trees" themed walk.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_04.jpg'),
  ('武康路', 4, 'Former Italian Consulate-General Residence (No. 390 Wukang Road)', '武康路 · 意大利总领事馆旧址', '<p>Located at No. 390 Wukang Road, this building was designed and built by Credit Foncier d''Extreme-Orient in 1932 as the Italian consul-general''s residence in Shanghai. The site covers about 2,630 m² with a floor area of 612 m², a half-basement + two above-ground-floor brick-and-stone mixed structure. The main façade faces south toward the garden; the east, south, and west sides of the ground floor are all open arcades, with red barrel-tile pitched roofs combined with semicircular and square window openings — one of Shanghai''s rare surviving Mediterranean-style garden residences. After 1949 it served as offices for Shanghai''s machinery and electrical systems; from 1995 it was assigned to SAIC Motor. After renovation, from 2024 it has operated as the "Mediterranean Lifestyle Hall" with reservation-based public access to the building, garden, and small art exhibitions.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_05.jpg'),
  ('武康路', 5, '武康庭（Wukang Mansion Courtyard / 武康路 376—378 号）', '武康路 · 武康庭', '<p>Wukang Mansion Courtyard sits at Nos. 376—378 Wukang Road, on the site of 1920s British firm Aquarius Co. (the famous "Zhèng Guǎng Hé" soda-water brand) Shanghai offices and surrounding new-style lilong. Renovated into an open commercial courtyard in 2007, it preserves historical elements such as the red-brick walls, dormer windows, and terrazzo stairs, and uses a central water feature, long wooden benches, and vine trellises to create an "European-style lilong atrium" atmosphere. The courtyard gathers specialty coffee shops (such as %Arabica, Peet''s Coffee, Manner pop-ups), independent designer boutiques, contemporary art galleries, wedding-dress ateliers, and light dining. It is the longest-paused "small and beautiful" complex on Wukang Road, directly connected to the street, free to enter, and one of the most iconic shooting spots for an "afternoon in Wukang Road."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_06.jpg'),
  ('武康路', 6, '原德利那齐宅）', '罗密欧阳台（武康路 210 号', '<p>Located at No. 210 Wukang Road and built in the 1930s, this was the private residence of Italian merchant Del Nerce. The building is a three-story brick-concrete Western-style house with cream-yellow walls, white window casings, and a small curved iron balcony projecting south from the second floor, facing the plane-tree-lined depths of Wukang Road. Seen from a distance, the balcony with its surrounding walls, vines, and garden forms a highly theatrical scene, hence its popular nickname "Romeo''s Balcony" (literally "Juliet''s Balcony") coined in the 2000s — the most romantic micro-landmark along Wukang Road. The building is privately owned and not open to the interior; visitors can view and photograph the façade from the Wukang Road sidewalk — an unmissable "view along the way" on a Wukang Road City Walk.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_07.jpg'),
  ('武康路', 7, 'Former Residence of Ba Jin (No. 113 Wukang Road)', '武康路 · 巴金故居', '<p>Located at No. 113 Wukang Road, this was Ba Jin''s residence from 1955 — when he moved here from Huaihai Lane — until his death in 2005, a span of nearly half a century and his longest-tenured Shanghai home with the highest output. The building is a three-bay two-story detached garden villa built in the 1920s, with simple gray-brick façades, a modest gate, and a garden preserving the magnolia and cherry trees Ba Jin himself planted. From 1958—2003, here he completed Random Thoughts (five volumes, 150 essays), True Words, In Sickness, and other major works, and hosted many Chinese and overseas scholars of his writing. Officially opened to the public in 2011, the interior retains the original arrangement of Ba Jin''s furniture, desk, bookcases, and phonograph. Exhibits include manuscripts, letters, photographs, books, and personal items of Ba Jin and his wife Xiao Shan.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_08.jpg'),
  ('武康路', 8, 'Medan Apartments）', '密丹公寓（武康路 115 号', '<p>Located at No. 115 Wukang Road, Medan Apartments was funded by the French International Savings Society and designed by the architectural firm A. Léonard &amp; P. Veysseyre in 1924. The building has six above-ground floors (originally four, later added), a brick-concrete structure, with yellow rough-cast cement walls and simple geometric window casings and balconies; the ground floor has a continuous arcade. Overall it shows the typical "Art Deco" early-modern style of the late 1920s. Located in the heart of the former French Concession next to the Ba Jin residence and Wukang Mansion Courtyard, it has long been rented by foreign doctors, engineers, and cultural celebrities. After 1949 it became ordinary residential housing for Shanghai citizens; the first and second floors are partly commercial, with residential units above. The exterior is open to view; the interior is not accessible — a must-stop on Wukang Road''s "Architecture Can Be Read" walk.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wukang_road_sa_09.jpg'),
  ('徐家汇源景区', 0, '', '徐家汇书院', '<p>Xujiahui Academy, which officially opened on New Year''s Day 2023, serves as the new Xuhui District Library and a core cultural landmark of the Xujiahui Yuan scenic area. Its facade was designed by Pritzker Prize laureate Sir David Chipperfield. The 18,650-square-meter building spans two basement levels and three above-ground floors. The signature space is a 14-meter-high atrium centered on a 20-meter-tall "YUE" book wall that cascades from the third floor to the first, with more than 800 reading seats scattered throughout. Located just one block from Xujiahui Catholic Church, its floor-to-ceiling windows frame the century-old Gothic Revival facade, creating a uniquely Shanghainese "read with a cathedral view" aesthetic.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_01.jpg'),
  ('徐家汇源景区', 1, '', '徐家汇天主堂', '<p>Officially named "St. Ignatius Cathedral," its construction was initiated by French Jesuits from 1851, with the current building designed by British architect W. M. Dowdall and completed in 1910. Built in red brick, the Latin-cross plan measures 79 meters long by 28 meters wide and once accommodated 2,500 worshippers, earning it the "L''Osservatore Romano" praise as the "First Cathedral of the Far East." The twin bell towers rise 60 meters, making it the largest and best-preserved Gothic Revival Catholic church in Shanghai. It was designated a Shanghai Municipal Cultural Relic in 1989 and a Major National Historical Site in 2013.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_02.jpg'),
  ('徐家汇源景区', 2, '', '上海气象博物馆（徐家汇观象台旧址）', '<p>The Xujiahui Observatory that houses the Shanghai Meteorological Museum was founded in 1872 by French Jesuits. In 1879 it issued China''s first typhoon warning, making it the country''s earliest typhoon-warning agency and one of Asia''s first meteorological observatories. The three-story brick-and-timber building, expanded in 1900, combines gray brick walls with a traditional Chinese xieshan roof and Western-style dormer windows—a fine example of early Sino-Western hybrid architecture. Its collection of 1,229 instruments and documents, including continuous weather records since 1872, is often called "the living archive of modern Chinese meteorology." It was listed as a Major National Historical Site in 2014.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_03.jpg'),
  ('徐家汇源景区', 3, '', '徐汇公学旧址（崇思楼）', '<p>Founded in 1850 by French missionary Claude Gotteland and named after St. Ignatius of Loyola, Xuhui Public School (now Shanghai Xuhui High School) was one of the earliest Western-style schools in Shanghai. The current Chongsi Building was designed in 1915 by Belgian priest-architect Désiré and completed in 1918. The three-story French Renaissance brick-and-timber structure stands in red brick with exquisite carved details, directly across from Grand Gateway 66. In 2014, it was incorporated into the Xujiahui Catholic Historical Architecture Complex and listed as a Major National Historical Site.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_04.jpg'),
  ('徐家汇源景区', 4, '', '百代小楼（《义勇军进行曲》灌制地纪念馆）', '<p>Located in Xujiahui Park, Baidai Villa was built in 1921 as the recording studio of Pathé-Orient (百代) Records. On May 3, 1935, the "March of the Volunteers" from the film "Children of Troubled Times" was recorded here and pressed for nationwide release, with music by Nie Er and lyrics by Tian Han, later becoming the national anthem of the People''s Republic of China. The two-story red-tile brick-and-timber building with a pebbledash exterior is the only surviving site in Shanghai where the national anthem was recorded. It opened to the public on May 1, 2021 as the "March of the Volunteers Recording Site Memorial," and its first-floor exhibition areas were opened in full after a 2024–2025 renovation.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_05.jpg'),
  ('徐家汇源景区', 5, '', '上海电影博物馆', '<p>Located at No. 595 Caoxi North Road on the original site of Shanghai Film Studio, the Shanghai Film Museum opened on June 16, 2013, the opening day of the Shanghai International Film Festival. It is one of the largest film-themed museums in China. The museum is divided into four themed halls: "Memory of Light and Shadow" traces Shanghai''s 100-year cinema history since the late 19th century; "Film Factory" reveals the production process; "River of Light" walks visitors through milestones of Chinese cinema; "Centennial Brilliance" pays tribute to Shanghai filmmakers. Special exhibitions on the first floor feature international masters. The collection includes more than 15,000 film artifacts and documents, including original posters and props from classics like "Song of the Fishermen" and "Children of Troubled Times."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_06.jpg'),
  ('徐家汇源景区', 6, '', '光启公园与徐光启纪念馆', '<p>Located at No. 17 Nandan East Road, Xuhui District, Guangqi Park was originally Nandan Park and was renamed in 1983 to mark the 350th anniversary of Xu Guangqi''s death. It is the only city park in central Shanghai named after an ancient scientist. The park contains the tombs of Xu Guangqi and his wife in a Ming-dynasty layout. The Xu Guangqi Memorial Hall, originally built in 1957, was closed in 2014 for a major renovation and reopened on January 8, 2016 (the 454th anniversary of Xu''s birth), with a second upgrade completed in 2021. It comprehensively showcases Xu''s Sino-Western synthesis in agronomy, astronomy, mathematics, and military science. The park itself is free and serves as the "literary landscape" segment of Xujiahui Yuan.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_07.jpg'),
  ('徐家汇源景区', 7, '', '土山湾博物馆', '<p>Located at No. 55 Puhuitang Road, the museum occupies the site of the Tushanwan Jesuit Orphanage. Founded in 1864 by French Jesuits, the orphanage became the earliest institution in China to systematically teach Western art and crafts, winning gold medals at the 1900 Paris, 1904 St. Louis, and 1915 Panama-Pacific international expositions—earning it the title "Cradle of Chinese Western Painting." The museum''s treasure is the 5.2-meter-tall three-tiered "Chinese Paifang" (memorial archway) carved in 1933 by orphanage woodworkers. The museum officially opened during the 2010 Shanghai World Expo, comprehensively showcasing Sino-Western artistic exchange from 1864 to 1960.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_08.png'),
  ('徐家汇源景区', 8, '', '圣母院旧址（上海老站）', '<p>The site faces Xujiahui Catholic Church in the heart of the Xujiahui Yuan scenic area. Built in 1929 with funds raised by the French Sisters of Our Lady of the Rescue and Presentation, it served as a convent dormitory and girls'' orphanage, and is part of the Xujiahui Catholic historical architecture complex. The five-story white French-style reinforced concrete building is elegantly understated. In 2001, the Benbang (local Shanghai) restaurant "Shanghai Old Station" took over the space, taking its name from the nearby original Shanghai North Railway Station (the starting point of the Shanghai–Nanjing Railway). The lawn once displayed Empress Dowager Cixi''s private train car and Soong Ching-ling''s official car (both moved out around 2023). Today it functions as a cultural dining space—the only "living building" in the scenic area that combines heritage protection with commercial use.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/xujiahui_source_scenic_area_sa_09.jpg'),
  ('豫园', 0, 'Sansui Hall', '三穗堂', '<p>A five-bay gable-roofed hall with a soaring ridge, it displays red-lacquered painted beams and a calligraphic plaque. Inside, a portrait of Pan Yuduan and an old panorama of the garden are exhibited. Today it welcomes visitors and frames the first impression of Yuyuan.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_01.jpg'),
  ('豫园', 1, 'Yangshan Hall & Juanyu Lou', '仰山堂·卷雨楼', '<p>Yangshan Hall is a three-bay gable-roofed room framing views of the rockery; Juanyu Lou above offers tea seats and, on rainy days, eaves that drip like a curtain—hence the name. The complex is the prime vantage point for photographing the Great Rockery.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_02.jpg'),
  ('豫园', 2, 'The Great Rockery', '大假山', '<p>Built of yellow stones from Wukang, Zhejiang, the 12-metre-tall, 400-metre-perimeter rockery features crags, caves and winding paths. From the summit pavilion, visitors glimpse the Huangpu River and City God Temple roofs. A national key cultural relic, it embodies the Ming literati principle of "made by man, yet appearing natural."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_03.jpg'),
  ('豫园', 3, 'Cuixiu Hall', '萃秀堂', '<p>Facing a winding pool and backed by rockwork, Cuixiu Hall is a three-bay hall on the eastern foot of the Great Rockery. Planted with osmanthus, magnolia, crabapple and crape myrtle, it served the Ming owners for poetry and music gatherings. Its pale Su-style painted beams and fine latticework reflect the classic Jiangnan literati aesthetic.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_04.jpg'),
  ('豫园', 4, 'Wanhua Lou', '万花楼', '<p>A two-storey structure next to Cuixiu Hall, named for the peonies, roses, camellias, azaleas and herbaceous peonies surrounding it. The ground floor is a flower-viewing parlor; the upper floor overlooks the pool and rockery. It is Yuyuan''s most beloved springtime destination.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_05.jpg'),
  ('豫园', 5, 'Dianchun Hall', '点春堂', '<p>Originally a guild hall for Fujianese sugar and flower merchants, Dianchun Hall became the command post of the 1853 Small Swords Society Uprising led by Liu Lichuan. Today a five-bay gable-roofed building with a front stage, it preserves exhibits about the uprising, making it both a revolutionary heritage site and a traditional opera venue.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_06.jpg'),
  ('豫园', 6, 'Yulinglong (Jade Camellia Stone)', '玉玲珑', '<p>A 3.3-metre-tall Lake Tai scholar''s rock, Yulinglong is famed for its 72 perforations, said to let smoke from a single incense burner escape through every hole. Once owned by the Ming official Gu Mingshi, it is one of the "Three Great Rocks of Jiangnan" alongside Liu Garden''s Guanyun Peak and West Lake''s Zhouyun Peak.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_07.jpg'),
  ('豫园', 7, 'Yuhua Hall', '玉华堂', '<p>Yuhua Hall ("Jade-Splendor Hall") is a compact three-bay studio adjoining the Jade Camellia Stone. Its name means "the essence of jade." Fitted with Ming-style furniture and surrounded by bamboo, rocks and a small pool, it was the owner''s retreat for reading and qin playing. Today it complements the Yulinglong stone display.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_08.jpg'),
  ('豫园', 8, 'Huijing Lou', '会景楼', '<p>The three-storey Huijing Lou ("Gathering-Scenery Tower") is the tallest building in Yuyuan''s west garden. Its top floor offers 360-degree views: the Nine-Turn Bridge and Mid-Lake Pavilion to the south, the Great Rockery and City God Temple to the east, and Lujiazui''s skyline to the northwest. It also houses calligraphy exhibitions and a tea house.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_09.jpg'),
  ('豫园', 9, 'Deyue Lou', '得月楼', '<p>Built by the lotus pond, Deyue Lou ("Moon-Winning Tower") is a two-storey teahouse facing the Mid-Lake Pavilion and the winding Nine-Turn Bridge. Its name quotes Su Lin of the Song dynasty: "The waterside tower wins the moon first." Tea and Shanghainese snacks are served upstairs with prime views—the quintessential Jiangnan teahouse experience.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_10.jpg'),
  ('豫园', 10, 'Inner Garden', '内园', '<p>Built in 1709 as a private garden for the City God Temple complex, the Inner Garden is a master class in Jiangnan miniature landscaping. In just 2 mu it packs winding corridors, the Nine-Dragon Pool, the Yellow-Stone Rockery and the Jiyu Peak, connected by covered walkways inset with Ming–Qing stone tablets—a perfectly preserved late-imperial literati garden.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/yu_garden_sa_11.jpg'),
  ('朱家角古镇', 0, 'Fangsheng Bridge', '放生桥', '<p>Spanning the Caogang River at the eastern entrance of Zhujiajiao, Fangsheng Bridge is a five-arch stone structure 72 m long, 5 m wide and 7.4 m high. Built entirely of granite and bluestone without any timber, it has survived 450+ years of floods and repairs and remains the most monumental ancient bridge in Shanghai.</p>', ''),
  ('朱家角古镇', 1, 'North Street (Bei Dajie)', '北大街', '<p>Stretching 1.5 km between Yongfeng Bridge and Fangsheng Bridge, North Street is paved with flagstones and flanked by Ming–Qing shophouses. It was designated a "Chinese Historic and Cultural Street" in 2005 and still hosts traditional crafts and old-brand shops like Handalong Sauce Garden and Tongtianhe Pharmacy.</p>', ''),
  ('朱家角古镇', 2, 'Handalong Sauce Garden', '涵大隆酱园', '<p>Established in the 1880s at No.138 North Street, Handalong is a classic front-shop-back-workshop soy-sauce brewery. Visitors can still see the century-old vats, the open-air sun-curing yard and the traditional three-month summer pressing technique, with its soy sauce listed as a Qingpu district intangible cultural heritage item.</p>', ''),
  ('朱家角古镇', 3, 'Tai''an Bridge', '泰安桥', '<p>A single-arch stone bridge 22 m long, Tai''an Bridge was originally built in the Wanli era and rebuilt in 1791. Crossing the Xijingting Port, it is famed for its finely carved railings and its location near the historic Xi family hall—part of Zhujiajiao''s most picturesque water-alley ensemble.</p>', ''),
  ('朱家角古镇', 4, 'Yuanjin Chan Temple', '圆津禅院', '<p>Founded in 1341 and rebuilt in the Wanli and Kangxi eras, Yuanjin Chan Temple is Zhujiajiao''s principal Buddhist temple, housing the Yan Guang Guanyin, the Goddess of Eyesight. Its "Yuanjin Dawn Bell" was one of the celebrated "Eight Views of Xijing" during the Ming–Qing period.</p>', ''),
  ('朱家角古镇', 5, 'Covered Bridge (Langqiao)', '廊桥', '<p>Built in 2001 in classical Jiangnan style, this 36 m covered bridge links North Street to Yuanjin Temple. With its flying eaves, red lanterns and river views, it is the modern symbol of Zhujiajiao and the most photographed spot on the Caogang River.</p>', ''),
  ('朱家角古镇', 6, 'City God Temple (Zhujiajiao Chenghuang Miao)', '城隍庙', '<p>Originally built in the Yongle era and rebuilt in 1775, the City God Temple is a 18th-century complex with an opera stage and side halls, dedicated to local city god Wang Ao. The temple hosts the famous "City God Parade" and the autumn Chongyang Festival market.</p>', ''),
  ('朱家角古镇', 7, 'Kezhi Garden', '课植园', '<p>Built 1912–1915 by Shanghai industrialist Ma Wenqing, Kezhi Garden covers ~40 mu and uniquely combines classic Jiangnan garden pavilions with rice paddies and vegetable plots—embodying the late-Qing ideal of combining study and farming. It now functions as a folk-art and photography museum.</p>', ''),
  ('朱家角古镇', 8, 'Da Qing Post Office', '大清邮局', '<p>Founded in 1903 at No.81 North Street, the Da Qing Post Office is the best-preserved Qing-era post office in East China. The two-story Sino-Western brick building now houses a postal museum with Qing dragon stamps, Republican overprints and a working post counter where visitors can mail postcards stamped with the "Zhujiajiao" postmark.</p>', '')
), mapped_rows AS (
  SELECT CONCAT(a.id, '_sa_', LPAD((i.sort_order + 1)::text, 2, '0')) AS id, a.id AS attraction_id, i.name_en, i.name_zh, i.body, i.cover_image_path, i.sort_order
  FROM input_rows i JOIN attractions a ON a.chinese_name = i.attraction_name_zh
)
INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
SELECT id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, TRUE FROM mapped_rows
ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_zh=EXCLUDED.name_zh, body=EXCLUDED.body, cover_image_path=EXCLUDED.cover_image_path, sort_order=EXCLUDED.sort_order, is_active=EXCLUDED.is_active, updated_at=NOW();
